     public TimedTestMethodAttribute(int warningThresholdMs = 5000, [CallerFilePath] string callerFilePath = "", [CallerLineNumber] int callerLineNumber = -1)
         : base(callerFilePath, callerLineNumber)
     {
         _warningThresholdMs = warningThresholdMs;
     }

     public override async Task<TestResult[]> ExecuteAsync(ITestMethod testMethod)
     {
         var sw = System.Diagnostics.Stopwatch.StartNew();
         var results = await base.ExecuteAsync(testMethod);
         sw.Stop();

         if (sw.ElapsedMilliseconds > _warningThresholdMs)
         {
             Console.WriteLine($"WARNING: {testMethod.TestMethodName} took {sw.ElapsedMilliseconds}ms (threshold: {_warningThresholdMs}ms)");
         }

         return results;
     }
 }

